- 'Made it to the playoffs' refers to teams that qualified for the postseason competition;
- 'Crowds swell to an average of more than 50,000 spectators' means the average attendance at their home games exceeded 50,000 people;
- 'Financial fortunes' refers to the average revenue generated from the games.

sql:
SELECT COUNT(DISTINCT team_id) AS total_teams_with_playoff_and_bowl_win
FROM team_performance
WHERE playoff_appearance = 1 AND bowl_win = 1;

SELECT T1.team_name
FROM teams AS T1
WHERE T1.playoff_appearances = (SELECT MAX(playoff_appearances) FROM teams);

SELECT SUM(playoff_appearances) 
FROM playoff_stats 
WHERE season = '2021';

